/**
 * CORS Utilities for Admin Portal Lambdas
 *
 * Implements dynamic CORS origin validation (1.3).
 *
 * Problem: HTTP API v2 does not support wildcard subdomain origins (e.g., *.login.example.com).
 * Solution: Validate the request Origin header at the Lambda level using regex patterns.
 *
 * Allowed origins:
 * - https://admin.{rootDomain}           — Admin Portal
 * - https://{tenantId}.login.{rootDomain} — SP Portal (all tenants)
 * - https://{tenantId}.idapersona.{rootDomain} — AMFA Service (all tenants)
 * - http://localhost:5173                 — Admin Portal local dev (Vite)
 * - http://localhost:3000                 — SP Portal local dev
 */

/**
 * Build allowed origin patterns from the root domain.
 * Called once per Lambda cold start and cached.
 *
 * @param {string} rootDomain - e.g., "amfac.aws-amplify.dev"
 * @returns {RegExp[]} Array of regex patterns for allowed origins
 */
function buildAllowedPatterns(rootDomain) {
    if (!rootDomain) {
        // Fallback: if no root domain configured, allow all (backward compat)
        return [/.*/];
    }

    // Escape dots for regex
    const escaped = rootDomain.replace(/\./g, '\\.');

    return [
        // Admin Portal: https://admin.{rootDomain}
        new RegExp(`^https:\\/\\/admin\\.${escaped}$`),
        // SP Portal: https://{tenantId}.login.{rootDomain}
        new RegExp(`^https:\\/\\/[a-z0-9][a-z0-9-]*\\.login\\.${escaped}$`),
        // AMFA Service: https://{tenantId}.idapersona.{rootDomain}
        new RegExp(`^https:\\/\\/[a-z0-9][a-z0-9-]*\\.idapersona\\.${escaped}$`),
        // Local development
        /^http:\/\/localhost:(3000|5173)$/,
    ];
}

// Cache patterns per Lambda instance (cold start only)
let _cachedPatterns = null;
let _cachedRootDomain = null;

/**
 * Get cached allowed origin patterns.
 * Reads ROOT_DOMAIN_NAME from environment on first call.
 *
 * @returns {RegExp[]}
 */
function getAllowedPatterns() {
    const rootDomain = process.env.ROOT_DOMAIN_NAME || process.env.AMFA_BASE_URL || '';
    if (!_cachedPatterns || _cachedRootDomain !== rootDomain) {
        _cachedPatterns = buildAllowedPatterns(rootDomain);
        _cachedRootDomain = rootDomain;
    }
    return _cachedPatterns;
}

/**
 * Validate a request origin against allowed patterns.
 *
 * @param {string|undefined} origin - The Origin header from the request
 * @returns {string} The validated origin to echo back, or empty string if not allowed
 */
export function getCorsOrigin(origin) {
    if (!origin) {
        return '';
    }

    const patterns = getAllowedPatterns();
    const isAllowed = patterns.some(p => p.test(origin));

    return isAllowed ? origin : '';
}

/**
 * Extract the Origin header from a Lambda event.
 * Handles both HTTP API v2 (lowercase headers) and REST API v1 (mixed case).
 *
 * @param {Object} event - Lambda event object
 * @returns {string|undefined} The Origin header value
 */
export function getOriginFromEvent(event) {
    const headers = event?.headers || {};
    return headers.origin || headers.Origin;
}

/**
 * Build standard CORS headers for a Lambda response.
 *
 * Usage:
 *   import { getCorsHeaders } from 'admin-auth/cors-utils';
 *   return { statusCode: 200, headers: getCorsHeaders(event), body: ... };
 *
 * @param {Object} event - Lambda event object (to read Origin header)
 * @returns {Object} CORS headers object
 */
export function getCorsHeaders(event) {
    const origin = getOriginFromEvent(event);
    const allowedOrigin = getCorsOrigin(origin);

    return {
        'Access-Control-Allow-Origin': allowedOrigin || '*',
        'Access-Control-Allow-Headers': 'Content-Type,Authorization,X-Api-Key,X-Requested-With,X-Tenant-Id',
        'Access-Control-Allow-Methods': 'OPTIONS,GET,POST,PUT,DELETE',
        'Content-Type': 'application/json',
        // Vary: Origin tells caches that the response varies by Origin header
        // Important for CDN/proxy caching when origin-specific responses are returned
        ...(allowedOrigin && allowedOrigin !== '*' ? { 'Vary': 'Origin' } : {}),
    };
}
